import SideBar from "./SideBar";
import './index.css';
import routes from "./routes";
import { BrowserRouter as Router, Route, Routes } from "react-router-dom";

const App = () => (
  <Router>
    <SideBar />
    <Routes>
      {routes.map(({ path, Component }, key) => (
        <Route path={path} key={key} element={<Component />} />
      ))}
    </Routes>
  </Router>
)

export default App;
